package ru.memearena.meme.application; import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.error.*; import ru.memearena.meme.domain.*; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.user.application.UserProfileService; import ru.memearena.user.infrastructure.UserProfileRepository; import java.net.*; import java.time.*; import java.util.*;
@Service public class MemeService { private final MemeRepository memes; private final UserProfileService users; private final UserProfileRepository userRepo; private final Clock clock; public MemeService(MemeRepository memes,UserProfileService users,UserProfileRepository userRepo,Clock clock){this.memes=memes;this.users=users;this.userRepo=userRepo;this.clock=clock;} @Transactional public Meme create(UUID uploaderId,String title,String imageUrl,String sourceUrl){var u=users.get(uploaderId); validateUrl(imageUrl,true); validateUrl(sourceUrl,false); String t=title==null?"":title.trim(); if(t.isBlank()||t.length()>120) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid title"); var m=memes.save(new Meme(UUID.randomUUID(),t,imageUrl.trim(),sourceUrl==null||sourceUrl.isBlank()?null:sourceUrl.trim(),uploaderId,Instant.now(clock))); u.incrementSubmittedMemes(Instant.now(clock)); userRepo.save(u); return m;} @Transactional(readOnly=true) public Meme get(UUID id){return memes.findById(id).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ErrorCode.MEME_NOT_FOUND,"Meme not found"));} @Transactional public Meme approve(UUID id){Meme m=get(id); m.approve(Instant.now(clock)); return m;} @Transactional public Meme reject(UUID id){Meme m=get(id); m.reject(Instant.now(clock)); return m;} static void validateUrl(String raw, boolean required){ if(raw==null||raw.isBlank()){ if(required) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid URL"); else return;} try{URI u=URI.create(raw.trim()); if(!("http".equalsIgnoreCase(u.getScheme())||"https".equalsIgnoreCase(u.getScheme()))||u.getHost()==null) throw new IllegalArgumentException();}catch(Exception e){throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.VALIDATION_ERROR,"Invalid URL");}} }
